class KNNGraphWrapper {
private:
    GraphData graph;
    bool is_built;
    bool debug_mode;
    bool verbose_queries;

    // Вспомогательная функция для инициализации
    void initGraph(int n, int k, int dim) {
        graph.num_nodes = n;
        graph.k = k;
        graph.dim = dim;
        graph.d_neighbors = nullptr;
        graph.d_distances = nullptr;
        graph.d_data = nullptr;
        is_built = false;

        if (debug_mode) std::cout << "[Init] Allocating GPU memory for " << n << " nodes, dim " << dim << std::endl;

        CUDA_CHECK(cudaMalloc(&graph.d_neighbors, n * k * sizeof(int)));
        CUDA_CHECK(cudaMalloc(&graph.d_distances, n * k * sizeof(float)));
        CUDA_CHECK(cudaMalloc(&graph.d_data, n * dim * sizeof(float)));
    }

    // Ядро CUDA: вычисление расстояний (упрощенно для примера)
    __global__ void computeDistancesKernel(const float* data, const float* query, float* dists, int n, int dim) {
        int idx = blockIdx.x * blockDim.x + threadIdx.x;
        if (idx < n) {
            float sum = 0.0f;
            for (int d = 0; d < dim; ++d) {
                float diff = data[idx * dim + d] - query[d];
                sum += diff * diff;
            }
            dists[idx] = sqrtf(sum);
        }
    }

    // Ядро CUDA: поиск k-NN (наивный для демонстрации, в реальности используется HNSW/IVF)
