public:
    KNNGraphWrapper(bool debug = false, bool verbose = false) : debug_mode(debug), verbose_queries(verbose), is_built(false) {
        if (debug_mode) {
            int device = 0;
            cudaGetDevice(&device);
            cudaDeviceProp prop;
            cudaGetDeviceProperties(&prop, device);
