        if (is_built) resetGraph();
        initGraph(n, 0, dim); // k=0 пока, будет установлено при построении

        CUDA_CHECK(cudaMemcpy(graph.d_data, data.data(), n * dim * sizeof(float), cudaMemcpyHostToDevice));
        if (debug_mode) std::cout << "[Load] Loaded " << n << " vectors of dim " << dim << " to GPU." << std::endl;
    }

    // 2. Построение графа KNN
    void buildGraph(int k) {
