        CUDA_CHECK(cudaMemset(graph.d_distances, 0, graph.num_nodes * k * sizeof(float)));

        if (debug_mode) std::cout << "[Build] Graph structure initialized." << std::endl;
    }

    // 3. Уточнение графа (Refinement)
