    }

    // 6. Сохранение графа
    void saveGraph(const std::string& filename) {
        if (!is_built) throw std::runtime_error("Graph not built");

        if (debug_mode) std::cout << "[Save] Saving graph to " << filename << "..." << std::endl;

        std::ofstream file(filename, std::ios::binary);
        if (!file) throw std::runtime_error("Failed to open file for writing");

        // Заголовок
        file.write(reinterpret_cast<const char*>(&graph.num_nodes), sizeof(int));
        file.write(reinterpret_cast<const char*>(&graph.k), sizeof(int));
        file.write(reinterpret_cast<const char*>(&graph.dim), sizeof(int));

        // Копируем данные с GPU на CPU для записи
        std::vector<int> h_neighbors(graph.num_nodes * graph.k);
        std::vector<float> h_distances(graph.num_nodes * graph.k);
        std::vector<float> h_data(graph.num_nodes * graph.dim);

        CUDA_CHECK(cudaMemcpy(h_neighbors.data(), graph.d_neighbors, graph.num_nodes * graph.k * sizeof(int), cudaMemcpyDeviceToHost));
        CUDA_CHECK(cudaMemcpy(h_distances.data(), graph.d_distances, graph.num_nodes * graph.k * sizeof(float), cudaMemcpyDeviceToHost));
        CUDA_CHECK(cudaMemcpy(h_data.data(), graph.d_data, graph.num_nodes * graph.dim * sizeof(float), cudaMemcpyDeviceToHost));

        file.write(reinterpret_cast<const char*>(h_neighbors.data()), h_neighbors.size() * sizeof(int));
        file.write(reinterpret_cast<const char*>(h_distances.data()), h_distances.size() * sizeof(float));
        file.write(reinterpret_cast<const char*>(h_data.data()), h_data.size() * sizeof(float));

        file.close();
        if (debug_mode) std::cout << "[Save] Graph saved successfully." << std::endl;
    }

    // 7. Загрузка графа
    void loadGraph(const std::string& filename) {
        if (debug_mode) std::cout << "[Load] Loading graph from " << filename << "..." << std::endl;

        std::ifstream file(filename, std::ios::binary);
        if (!file) throw std::runtime_error("Failed to open file for reading");

        int n, k, dim;
        file.read(reinterpret_cast<char*>(&n), sizeof(int));
        file.read(reinterpret_cast<char*>(&k), sizeof(int));
        file.read(reinterpret_cast<char*>(&dim), sizeof(int));

        if (is_built) resetGraph();
        initGraph(n, k, dim);

        std::vector<int> h_neighbors(n * k);
        std::vector<float> h_distances(n * k);
        std::vector<float> h_data(n * dim);

        file.read(reinterpret_cast<char*>(h_neighbors.data()), h_neighbors.size() * sizeof(int));
        file.read(reinterpret_cast<char*>(h_distances.data()), h_distances.size() * sizeof(float));
        file.read(reinterpret_cast<char*>(h_data.data()), h_data.size() * sizeof(float));

        CUDA_CHECK(cudaMemcpy(graph.d_neighbors, h_neighbors.data(), n * k * sizeof(int), cudaMemcpyHostToDevice));
        CUDA_CHECK(cudaMemcpy(graph.d_distances, h_distances.data(), n * k * sizeof(float), cudaMemcpyHostToDevice));
        CUDA_CHECK(cudaMemcpy(graph.d_data, h_data.data(), n * dim * sizeof(float), cudaMemcpyHostToDevice));

        is_built = true;
        if (debug_mode) std::cout << "[Load] Graph loaded successfully." << std::endl;
    }

    // 8. Сброс графа для подмножества
    void resetGraph(int new_size = -1) {
        if (debug_mode) std::cout << "[Reset] Resetting graph..." << std::endl;

        if (graph.d_neighbors) {
            cudaFree(graph.d_neighbors);
            graph.d_neighbors = nullptr;
        }
        if (graph.d_distances) {
            cudaFree(graph.d_distances);
            graph.d_distances = nullptr;
        }
        if (graph.d_data) {
            cudaFree(graph.d_data);
            graph.d_data = nullptr;
        }

        if (new_size > 0) {
            // Если указан размер, инициализируем заново (например, для подмножества)
            // В реальном сценарии нужно загрузить данные подмножества
            initGraph(new_size, graph.k, graph.dim);
        } else {
            // Полная очистка
            graph.num_nodes = 0;
            graph.k = 0;
            graph.dim = 0;
            is_built = false;
        }
    }

    // 9. Выполнение запросов
    void query(const std::vector<float>& query_vector, int k, std::vector<int>& out_indices, std::vector<float>& out_dists) {
        if (!is_built) throw std::runtime_error("Graph not built");
        if (query_vector.size() != (size_t)graph.dim) throw std::runtime_error("Query dimension mismatch");

        if (verbose_queries) {
            std::cout << "[Query] Processing query for " << graph.num_nodes << " nodes..." << std::endl;
        }

        // Выделяем память для результата на GPU (временную)
        int* d_q_neighbors;
        float* d_q_dists;
        CUDA_CHECK(cudaMalloc(&d_q_neighbors, k * sizeof(int)));
        CUDA_CHECK(cudaMalloc(&d_q_dists, k * sizeof(float)));

        // Копируем запрос на GPU
        float* d_query;
        CUDA_CHECK(cudaMalloc(&d_query, graph.dim * sizeof(float)));
        CUDA_CHECK(cudaMemcpy(d_query, query_vector.data(), graph.dim * sizeof(float), cudaMemcpyHostToDevice));

        // Запуск ядра поиска (в примере заглушка)
        int threads = 256;
        int blocks = (k + threads - 1) / threads;
        knnSearchKernel<<<blocks, threads>>>(graph.d_data, nullptr, d_q_neighbors, d_q_dists, 
                                             graph.num_nodes, k, graph.dim, 0);
        CUDA_CHECK(cudaGetLastError());
        CUDA_CHECK(cudaDeviceSynchronize());

        // Копируем результат обратно
        out_indices.resize(k);
        out_dists.resize(k);
        CUDA_CHECK(cudaMemcpy(out_indices.data(), d_q_neighbors, k * sizeof(int), cudaMemcpyDeviceToHost));
        CUDA_CHECK(cudaMemcpy(out_dists.data(), d_q_dists, k * sizeof(float), cudaMemcpyDeviceToHost));

        // Очистка временной памяти
        cudaFree(d_q_neighbors);
        cudaFree(d_q_dists);
        cudaFree(d_query);

        if (verbose_queries) {
            std::cout << "[Query] Found " << k << " neighbors. Top dist: " << out_dists[0] << std::endl;
        }
    }
};

