}

// Основной пайплайн
const build = series(
    cleanDist,
    createDirectories,
    parallel(generateParsers, compileTemplates, processStyles),
    buildScripts,
    copyHtml,
    buildIndex
);

// Режим разработки с наблюдением
function watchFiles() {
    watch(paths.src.parsers, generateParsers);
    watch(paths.src.templates, compileTemplates);
    watch(paths.src.styles, processStyles);
    watch(paths.src.scripts, buildScripts);
}

// Экспорт задач
